{"version":3,"file":"foodRecommendation.js","sources":["pages/foodRecommendation/foodRecommendation.vue","../devolope_tool/HBuilderX/plugins/uniapp-cli-vite/uniPage:/cGFnZXMvZm9vZFJlY29tbWVuZGF0aW9uL2Zvb2RSZWNvbW1lbmRhdGlvbi52dWU"],"sourcesContent":["<template>\n  <view class=\"container\">\n    <!-- 头部导航栏 -->\n    <view class=\"header\">\n      <!-- <uni-icons type=\"back\" size=\"24\" color=\"#333\" @click=\"goBack\"/> -->\n      <text class=\"header-title\">美食推荐</text>\n      <uni-icons type=\"search\" size=\"24\" color=\"#333\" @click=\"onSearch\"/>\n    </view>\n\n    <!-- 主内容区域 -->\n    <view class=\"main\">\n      <!-- 筛选标签 -->\n      <scroll-view class=\"filter-scroll\" scroll-x>\n        <view class=\"filter-tags\">\n          <view \n            v-for=\"(tag, index) in filterTags\" \n            :key=\"index\"\n            :class=\"['filter-tag', { active: tag.active }]\"\n            @click=\"selectTag(index)\"\n          >\n            {{ tag.name }}\n          </view>\n        </view>\n      </scroll-view>\n\n      <!-- 排序选择器 -->\n      <view class=\"sort-selector\">\n        <text class=\"sort-text\">综合排序</text>\n        <uni-icons type=\"down\" size=\"12\" color=\"#999\"/>\n      </view>\n\n      <!-- 餐厅列表 -->\n      <scroll-view scroll-y class=\"restaurant-list\">\n        <view \n          v-for=\"(restaurant, index) in restaurants\" \n          :key=\"index\" \n          class=\"restaurant-card\"\n        >\n          <view class=\"restaurant-image\">\n            <image :src=\"restaurant.image\" mode=\"aspectFill\"/>\n            <text :class=\"['tag', restaurant.tagType]\">{{ restaurant.tag }}</text>\n          </view>\n          <view class=\"restaurant-info\">\n            <text class=\"restaurant-name\">{{ restaurant.name }}</text>\n            <view class=\"rating-box\">\n              <uni-icons type=\"star-filled\" size=\"14\" color=\"#FFA500\"/>\n              <text class=\"rating\">{{ restaurant.rating }}</text>\n              <text class=\"monthly-sale\">月售 {{ restaurant.monthlySales }}</text>\n            </view>\n            <view class=\"price-distance\">\n              <text class=\"price\">人均 ¥{{ restaurant.averagePrice }}</text>\n              <text class=\"distance\">距离 {{ restaurant.distance }}km</text>\n            </view>\n          </view>\n        </view>\n      </scroll-view>\n    </view>\n\n    <!-- 悬浮按钮 -->\n    <view class=\"float-button\">\n      <uni-icons type=\"calendar\" size=\"24\" color=\"#FFFFFF\"/>\n    </view>\n\n    \n  </view>\n</template>\n\n<script setup>\nimport { ref } from 'vue';\n\nconst currentTab = ref(0);\n\nconst filterTags = ref([\n  { name: '全部', active: true },\n  { name: '海鲜', active: false },\n  { name: '粤式', active: false },\n  { name: '特色小吃', active: false },\n  { name: '农家菜', active: false }\n]);\n\n\n\nconst restaurants = ref([\n  {\n    image: 'https://ai-public.mastergo.com/ai/img_res/a256aeabf41e28db3c1c0b25aec7373c.jpg',\n    name: '万山渔港海鲜餐厅',\n    rating: '4.8',\n    monthlySales: '2380',\n    averagePrice: '188',\n    distance: '1.2',\n    tag: '人气网红',\n    tagType: 'popular'\n  },\n  {\n    image: 'https://ai-public.mastergo.com/ai/img_res/6dcb4b894c7f14fcac90ab68d7dc378e.jpg',\n    name: '粤海味道',\n    rating: '4.6',\n    monthlySales: '1680',\n    averagePrice: '128',\n    distance: '0.8',\n    tag: '特色推荐',\n    tagType: 'featured'\n  }\n]);\n\nconst selectTag = (index) => {\n  filterTags.value.forEach((tag, i) => {\n    tag.active = i === index;\n  });\n};\n\nconst switchTab = (index) => {\n  currentTab.value = index;\n};\n\nconst goBack = () => {\n  uni.navigateBack();\n};\n\nconst onSearch = () => {\n  uni.showToast({\n    title: '搜索功能开发中',\n    icon: 'none'\n  });\n};\n</script>\n\n<style>\n/* 样式部分保持不变 */\npage {\n  height: 100%;\n}\n\n.container {\n  display: flex;\n  flex-direction: column;\n  height: 100%;\n  background-color: #FFFFFF;\n}\n\n.header {\n  position: fixed;\n  top: 0;\n  left: 0;\n  right: 0;\n  height: 88rpx;\n  background: #FFFFFF;\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  padding: 0 32rpx;\n  border-bottom: 1px solid #f5f5f5;\n  z-index: 100;\n}\n\n.header-title {\n  font-size: 16px;\n  font-weight: 500;\n  color: #333333;\n}\n\n.main {\n  flex: 1;\n  margin-top: 88rpx;\n  padding: 0 32rpx;\n  overflow: hidden;\n}\n\n.filter-scroll {\n  margin: 0 -32rpx;\n  padding: 24rpx 32rpx;\n  white-space: nowrap;\n}\n\n.filter-tags {\n  display: inline-flex;\n  gap: 24rpx;\n}\n\n.filter-tag {\n  display: inline-block;\n  padding: 12rpx 24rpx;\n  border-radius: 32rpx;\n  border: 1px solid #E5E5E5;\n  font-size: 14px;\n  color: #666666;\n}\n\n.filter-tag.active {\n  color: #0066FF;\n  border-color: #0066FF;\n  background-color: rgba(0, 102, 255, 0.1);\n}\n\n.sort-selector {\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n  margin: 32rpx 0;\n  padding: 16rpx;\n  background-color: #F5F5F5;\n  border-radius: 16rpx;\n}\n\n.sort-text {\n  font-size: 14px;\n  color: #666666;\n}\n\n.restaurant-list {\n  height: calc(100vh - 400rpx);\n  overflow: auto;\n}\n\n.restaurant-card {\n  margin-bottom: 32rpx;\n  border-radius: 16rpx;\n  overflow: hidden;\n  background: #FFFFFF;\n  box-shadow: 0 4rpx 16rpx rgba(0, 0, 0, 0.05);\n}\n\n.restaurant-image {\n  position: relative;\n  height: 360rpx;\n}\n\n.restaurant-image image {\n  width: 100%;\n  height: 100%;\n}\n\n.tag {\n  position: absolute;\n  top: 16rpx;\n  left: 16rpx;\n  padding: 8rpx 16rpx;\n  border-radius: 8rpx;\n  font-size: 12px;\n  color: #FFFFFF;\n}\n\n.tag.popular {\n  background-color: #FF6B00;\n}\n\n.tag.featured {\n  background-color: #0066FF;\n}\n\n.restaurant-info {\n  padding: 24rpx;\n}\n\n.restaurant-name {\n  font-size: 16px;\n  font-weight: 500;\n  color: #333333;\n  margin-bottom: 16rpx;\n}\n\n.rating-box {\n  display: flex;\n  align-items: center;\n  margin-bottom: 16rpx;\n}\n\n.rating {\n  font-size: 14px;\n  color: #333333;\n  margin: 0 16rpx 0 8rpx;\n}\n\n.monthly-sale {\n  font-size: 14px;\n  color: #999999;\n}\n\n.price-distance {\n  display: flex;\n  justify-content: space-between;\n  font-size: 14px;\n}\n\n.price {\n  color: #666666;\n}\n\n.distance {\n  color: #999999;\n}\n\n.float-button {\n  position: fixed;\n  right: 32rpx;\n  bottom: 140rpx;\n  width: 100rpx;\n  height: 100rpx;\n  background: #0066FF;\n  border-radius: 50%;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  box-shadow: 0 6rpx 20rpx rgba(0, 102, 255, 0.3);\n}\n\n\n</style>","import MiniProgramPage from 'D:/travel-master/pages/foodRecommendation/foodRecommendation.vue'\nwx.createPage(MiniProgramPage)"],"names":["ref","uni","MiniProgramPage"],"mappings":";;;;;;;;;;;;;AAsEmBA,kBAAG,IAAC,CAAC;AAExB,UAAM,aAAaA,cAAAA,IAAI;AAAA,MACrB,EAAE,MAAM,MAAM,QAAQ,KAAM;AAAA,MAC5B,EAAE,MAAM,MAAM,QAAQ,MAAO;AAAA,MAC7B,EAAE,MAAM,MAAM,QAAQ,MAAO;AAAA,MAC7B,EAAE,MAAM,QAAQ,QAAQ,MAAO;AAAA,MAC/B,EAAE,MAAM,OAAO,QAAQ,MAAO;AAAA,IAChC,CAAC;AAID,UAAM,cAAcA,cAAAA,IAAI;AAAA,MACtB;AAAA,QACE,OAAO;AAAA,QACP,MAAM;AAAA,QACN,QAAQ;AAAA,QACR,cAAc;AAAA,QACd,cAAc;AAAA,QACd,UAAU;AAAA,QACV,KAAK;AAAA,QACL,SAAS;AAAA,MACV;AAAA,MACD;AAAA,QACE,OAAO;AAAA,QACP,MAAM;AAAA,QACN,QAAQ;AAAA,QACR,cAAc;AAAA,QACd,cAAc;AAAA,QACd,UAAU;AAAA,QACV,KAAK;AAAA,QACL,SAAS;AAAA,MACV;AAAA,IACH,CAAC;AAED,UAAM,YAAY,CAAC,UAAU;AAC3B,iBAAW,MAAM,QAAQ,CAAC,KAAK,MAAM;AACnC,YAAI,SAAS,MAAM;AAAA,MACvB,CAAG;AAAA,IACH;AAUA,UAAM,WAAW,MAAM;AACrBC,oBAAAA,MAAI,UAAU;AAAA,QACZ,OAAO;AAAA,QACP,MAAM;AAAA,MACV,CAAG;AAAA,IACH;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;AC3HA,GAAG,WAAWC,SAAe;"}
